INSERT INTO maxkb.public.application VALUES('2024-05-22 21:02:06.98016+08', '2024-05-22 21:02:06.980195+08', '7e1dce56-183b-11ef-b1f8-0242ac110002', '知识问答机器人', '', '您好，我是 MaxKB 小助手，您可以向我提出 MaxKB 使用问题。', 3, '{"top_n": 3, "similarity": 0.6, "search_mode": "embedding", "no_references_setting": {"value": "{question}", "status": "ai_questioning"}, "max_paragraph_char_number": 5000}', '{"prompt": "已知信息：\n{data}\n回答要求：\n- 请使用简洁且专业的语言来回答用户的问题。\n- 如果你不知道答案，请回答“没有在知识库中查找到相关信建议咨询相关技术支持或参考官方文档进行操作”。\n- 避免提及你是从已知信息中获得的知识。\n- 请保证答案与已知信息中描述的一致。\n- 请使用 Markdown 语法优化答案的格式。\n- 已知信息中的     图片、链接地址和脚本语言请直接返回。\n- 请使用与问题相同的语言来回答。\n问题：\n{question}\n"}', 't', '454dba88-18b2-11ef-bd1f-0242ac170010', 'f0dd8f71-e4ee-11ee-8c84-a8a1595801ab', 'ui/favicon.ico');
